class Solution:
    def isRationalEqual(self, s, t):
        # Independent approach: expand each number to many decimal digits as an
        # exact integer scaled value, comparing far past any repeat period.
        from fractions import Fraction
        def to_fraction(x):
            if '.' not in x:
                return Fraction(int(x), 1)
            intpart, rest = x.split('.')
            base = Fraction(int(intpart) if intpart else 0, 1)
            if '(' in rest:
                nonrep, rep = rest.split('(')
                rep = rep[:-1]
            else:
                nonrep, rep = rest, ''
            a = len(nonrep)
            if nonrep:
                base += Fraction(int(nonrep), 10 ** a)
            if rep:
                b = len(rep)
                base += Fraction(int(rep), (10 ** b - 1) * (10 ** a))
            return base
        return to_fraction(s) == to_fraction(t)

