class Solution:
    def isRationalEqual(self, s, t):
        from fractions import Fraction
        def parse(x):
            if '.' not in x:
                return Fraction(int(x))
            i, r = x.split('.')
            total = Fraction(int(i)) if i else Fraction(0)
            if '(' in r:
                nonrep, rep = r.split('(')
                rep = rep.rstrip(')')
            else:
                nonrep, rep = r, ''
            a = len(nonrep)
            if nonrep:
                total += Fraction(int(nonrep), 10 ** a)
            if rep:
                b = len(rep)
                total += Fraction(int(rep), (10 ** b - 1) * 10 ** a)
            return total
        return parse(s) == parse(t)

