var isRationalEqual = function(s, t) {
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a < 0n ? -a : a; }
    function frac(num, den) {
        if (den < 0n) { num = -num; den = -den; }
        const g = gcd(num < 0n ? -num : num, den) || 1n;
        return [num / g, den / g];
    }
    function add(p, q) {
        return frac(p[0] * q[1] + q[0] * p[1], p[1] * q[1]);
    }
    function parse(x) {
        if (x.indexOf('.') === -1) return frac(BigInt(x), 1n);
        const dot = x.indexOf('.');
        const i = x.slice(0, dot);
        let r = x.slice(dot + 1);
        let total = frac(i === '' ? 0n : BigInt(i), 1n);
        let nonrep = r, rep = '';
        const open = r.indexOf('(');
        if (open !== -1) {
            nonrep = r.slice(0, open);
            rep = r.slice(open + 1, r.length - 1);
        }
        const a = BigInt(nonrep.length);
        if (nonrep.length > 0) {
            total = add(total, frac(BigInt(nonrep), 10n ** a));
        }
        if (rep.length > 0) {
            const b = BigInt(rep.length);
            total = add(total, frac(BigInt(rep), (10n ** b - 1n) * (10n ** a)));
        }
        return total;
    }
    const p = parse(s), q = parse(t);
    return p[0] === q[0] && p[1] === q[1];
};
